// ╔════════════════════════════════════════════════════════════════╗
// ║ PLACEHOLDER — regenerated by `npm run build`.                  ║
// ║                                                                ║
// ║ Replace this stub by running, from the component directory:    ║
// ║                                                                ║
// ║   npm install                                                  ║
// ║   npm run build                                                ║
// ║                                                                ║
// ║ That fetches the openWakeWord pipeline models, copies the ONNX ║
// ║ Runtime Web WASM artefacts, and bundles src/wake_word.js into  ║
// ║ this file. The real bundle is ~1.5 MB.                         ║
// ╚════════════════════════════════════════════════════════════════╝
(function () {
  function postStatus(status, error) {
    window.parent.postMessage({
      isStreamlitMessage: true,
      type: 'streamlit:setComponentValue',
      value: { __status: status, error: error || null, ts: Date.now() },
      dataType: 'json',
    }, '*');
  }
  function ready() {
    window.parent.postMessage(
      { isStreamlitMessage: true, type: 'streamlit:componentReady', apiVersion: 1 },
      '*'
    );
    window.parent.postMessage(
      { isStreamlitMessage: true, type: 'streamlit:setFrameHeight', height: 64 },
      '*'
    );
  }
  window.addEventListener('DOMContentLoaded', function () {
    var root = document.getElementById('root');
    if (root) {
      root.innerHTML =
        '<div class="ww-pill ww-pill-error">' +
        '<span class="ww-spinner"></span>' +
        '<span class="ww-status-text">Bundle not built — run npm run build</span>' +
        '</div>';
    }
    ready();
    postStatus(
      'ERROR',
      'Placeholder bundle. Run `npm install && npm run build` inside ' +
        'app/components/wake_word_continuous/ to generate the real ' +
        'dist/wake_word.bundle.js (see README.md). Until then, the ' +
        'kiosk falls back to the START/STOP push-to-talk pill.'
    );
  });
})();
